'use client';

/**
 * SocialProofSection — "Proven Across the Fortune 500" section
 * for TARGA AI site.
 *
 * Drop-in replacement. All logos are embedded as base64 data URIs
 * so there are no external file dependencies.
 *
 * Uses TARGA brand tokens:
 *   Navy: #1f476a
 *   Teal: #0eb2af
 *   Space Grotesk 300wt for headings
 *   Inter for body/UI
 */

const logos = [
  { alt: 'Johnson & Johnson', src: 'data:image/svg+xml;base64,' },
  { alt: 'DuPont', src: 'data:image/svg+xml;base64,' },
  { alt: 'Merck', src: 'data:image/svg+xml;base64,' },
  { alt: 'AT&T', src: 'data:image/svg+xml;base64,' },
  { alt: 'IBM', src: 'data:image/svg+xml;base64,' },
  { alt: 'Herman Miller', src: 'data:image/svg+xml;base64,' },
  { alt: 'Cigna', src: 'data:image/svg+xml;base64,' },
  { alt: 'Lilly', src: 'data:image/svg+xml;base64,' },
];

export default function SocialProofSection() {
  return (
    <section style={{
      padding: '80px 48px 64px',
      position: 'relative',
    }}>
      {/* Section label */}
      <div style={{
        display: 'flex',
        alignItems: 'center',
        gap: '16px',
        marginBottom: '24px',
      }}>
        <div style={{
          width: '40px',
          height: '1px',
          background: '#0eb2af',
        }} />
        <span style={{
          fontFamily: 'Inter, sans-serif',
          fontSize: '12px',
          fontWeight: 500,
          letterSpacing: '0.15em',
          textTransform: 'uppercase',
          color: 'rgba(255,255,255,0.4)',
        }}>
          Proven across the Fortune 500
        </span>
      </div>

      {/* Body copy */}
      <p style={{
        fontFamily: 'Inter, sans-serif',
        fontSize: '16px',
        fontWeight: 400,
        lineHeight: 1.7,
        color: 'rgba(255,255,255,0.55)',
        maxWidth: '640px',
        marginBottom: '56px',
      }}>
        TARGA was built on decades of hands-on transformation work with the
        world&apos;s most demanding leadership teams. The methodology behind the
        platform was forged inside these organizations.
      </p>

      {/* Logo bar */}
      <div style={{
        display: 'flex',
        flexWrap: 'wrap',
        alignItems: 'center',
        justifyContent: 'space-between',
        gap: '32px 24px',
        paddingBottom: '48px',
        borderBottom: '1px solid rgba(14, 178, 175, 0.15)',
      }}>
        {logos.map((logo) => (
          <img
            key={logo.alt}
            src={logo.src}
            alt={logo.alt}
            draggable={false}
            style={{
              height: '22px',
              maxWidth: '140px',
              width: 'auto',
              objectFit: 'contain',
              opacity: 0.7,
              transition: 'opacity 0.3s ease',
              flexShrink: 0,
            }}
            onMouseEnter={(e) => { e.currentTarget.style.opacity = '0.9'; }}
            onMouseLeave={(e) => { e.currentTarget.style.opacity = '0.7'; }}
          />
        ))}
      </div>
    </section>
  );
}
